import { useEffect, useRef, useState, useCallback } from "react";
import axios from "axios";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8002";
const ANALYZE_URL_EP = `${API_BASE}/analyze-url`;
const ASK_URL_EP = `${API_BASE}/ask-question`;
const SUBMIT_CREDS_URL = `${API_BASE}/submit-credentials`;
const END_SESSION_URL = `${API_BASE}/session/end`;

axios.defaults.withCredentials = true;

const isProbablyUrl = (v) => /^https?:\/\/\S+$/i.test((v || "").trim());

const parseApiError = (err) => {
  const status = err?.response?.status;
  const detail = err?.response?.data?.detail;
  if (detail && typeof detail === "object") {
    return {
      status,
      message: detail.message || "Request failed.",
      authTypes: Array.isArray(detail.auth_types) ? detail.auth_types : [],
      requiredFields: Array.isArray(detail.required_fields) ? detail.required_fields : [],
    };
  }
  return {
    status,
    message: typeof detail === "string" ? detail : "Failed to get response from server.",
    authTypes: [],
    requiredFields: [],
  };
};

const SESSION_DURATION = 3 * 60 * 60 * 1000;

// Human-friendly field labels
const FIELD_LABELS = {
  email: "Email Address",
  username: "Username",
  password: "Password",
  otp: "One-Time Password (OTP)",
  pin: "PIN",
  verification_code: "Verification Code",
};

const FIELD_TYPES = {
  email: "email",
  username: "text",
  password: "password",
  otp: "text",
  pin: "text",
  verification_code: "text",
};

function SessionTimer({ startTime }) {
  const [remaining, setRemaining] = useState(SESSION_DURATION);
  useEffect(() => {
    if (!startTime) return;
    const tick = () => setRemaining(Math.max(0, SESSION_DURATION - (Date.now() - startTime)));
    tick();
    const iv = setInterval(tick, 1000);
    return () => clearInterval(iv);
  }, [startTime]);

  const h = Math.floor(remaining / 3600000);
  const m = Math.floor((remaining % 3600000) / 60000);
  const s = Math.floor((remaining % 60000) / 1000);
  const pct = (remaining / SESSION_DURATION) * 100;
  const color = pct > 50 ? "#00ff9d" : pct > 20 ? "#ffb800" : "#ff4545";

  return (
    <div className="session-timer">
      <div className="timer-label">SESSION EXPIRES IN</div>
      <div className="timer-value" style={{ color }}>
        {String(h).padStart(2,"0")}:{String(m).padStart(2,"0")}:{String(s).padStart(2,"0")}
      </div>
      <div className="timer-bar-track">
        <div className="timer-bar-fill" style={{ width: `${pct}%`, background: color }} />
      </div>
    </div>
  );
}

export default function App() {
  const [urlInput, setUrlInput] = useState("");
  const [question, setQuestion] = useState("");
  const [sessionId, setSessionId] = useState("");
  const [sessionStart, setSessionStart] = useState(null);
  const [activeUrl, setActiveUrl] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  // phase: idle | analyzing | authing | chatting | blocked
  const [phase, setPhase] = useState("idle");
  const [authRequired, setAuthRequired] = useState(false);
  const [requiredFields, setRequiredFields] = useState([]);
  const [authTypes, setAuthTypes] = useState([]);
  const [creds, setCreds] = useState({ email: "", username: "", password: "", otp: "", pin: "", verification_code: "" });
  const [error, setError] = useState("");
  const [urlLocked, setUrlLocked] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  useEffect(() => {
    if (!sessionId) return;
    const handler = () => {
      navigator.sendBeacon(END_SESSION_URL, new Blob([JSON.stringify({ session_id: sessionId })], { type: "application/json" }));
    };
    window.addEventListener("beforeunload", handler);
    return () => window.removeEventListener("beforeunload", handler);
  }, [sessionId]);

  const addMsg = (role, content) =>
    setMessages((prev) => [...prev, { role, content, ts: Date.now() }]);

  const saveSession = (sid) => {
    if (sid && !sessionId) {
      setSessionId(sid);
      setSessionStart(Date.now());
    }
  };

  // ── ANALYZE URL ────────────────────────────────────────────────────────────
  const handleAnalyze = useCallback(async (overrideUrl) => {
    const url = (overrideUrl || urlInput).trim();
    if (!url) return;
    setError("");
    setLoading(true);
    setPhase("analyzing");
    setUrlLocked(true);
    addMsg("system", `Scanning → ${url}`);

    try {
      const resp = await axios.get(ANALYZE_URL_EP, { params: { url } });
      const { login_required, auth_types, required_fields, session_id, final_url } = resp.data;
      saveSession(session_id);
      setActiveUrl(final_url || url);

      if (login_required) {
        setAuthRequired(true);
        setAuthTypes(auth_types || []);
        setRequiredFields(required_fields || ["username", "password"]);
        setPhase("authing");

        const fieldList = (required_fields || ["username", "password"])
          .map((f) => FIELD_LABELS[f] || f)
          .join(", ");

        addMsg("assistant",
          `🔐 **This page requires authentication.**\n\n` +
          `**Auth type detected:** \`${(auth_types || []).join(", ") || "username/password"}\`\n\n` +
          `**Please provide:** ${fieldList}\n\n` +
          `Fill in the form on the left and click **Submit Credentials** to continue.`
        );
      } else {
        setPhase("chatting");
        addMsg("assistant",
          `✅ **Page loaded successfully!**\n\nThe page is publicly accessible. ` +
          `You can now ask me anything about its content.`
        );
      }
    } catch (err) {
      const e = parseApiError(err);
      setError(e.message);
      addMsg("system", `❌ Error: ${e.message}`);
      setPhase("idle");
      setUrlLocked(false);
    } finally {
      setLoading(false);
    }
  }, [urlInput, sessionId]);

  // ── SUBMIT CREDENTIALS ─────────────────────────────────────────────────────
  const handleSubmitCredentials = async () => {
    if (!activeUrl || loading) return;
    setError("");
    setLoading(true);

    try {
      const payload = { url: activeUrl };
      if (creds.email.trim())             payload.email             = creds.email.trim();
      if (creds.username.trim())          payload.username          = creds.username.trim();
      if (creds.password)                 payload.password          = creds.password;
      if (creds.otp.trim())              payload.otp               = creds.otp.trim();
      if (creds.pin.trim())              payload.pin               = creds.pin.trim();
      if (creds.verification_code.trim()) payload.verification_code = creds.verification_code.trim();

      const resp = await axios.post(SUBMIT_CREDS_URL, payload);
      const { authenticated, message, next_required_fields, next_required, session_id } = resp.data;
      saveSession(session_id);

      if (authenticated) {
        // ✅ SUCCESS — clear auth state, move to chat
        setAuthRequired(false);
        setRequiredFields([]);
        setAuthTypes([]);
        setPhase("chatting");
        setCreds({ email: "", username: "", password: "", otp: "", pin: "", verification_code: "" });
        addMsg("assistant",
          `✅ **${message}**\n\n` +
          `You're now logged in. Ask me anything about this page's content!`
        );
      } else {
        // ❌ FAILED — show specific reason and what's needed next
        const nextFields = next_required_fields || [];
        const isBlocked = (next_required || []).includes("captcha") || (next_required || []).includes("sso");

        if (isBlocked) {
          setPhase("blocked");
          setAuthRequired(false);
          addMsg("assistant",
            `🚫 **Login blocked by the site.**\n\n${message}\n\n` +
            `**What you can do:**\n` +
            `- Try a different URL that uses simple username/password login\n` +
            `- Use a page that doesn't require Google/GitHub/SSO sign-in\n` +
            `- Reset the session and try another site`
          );
        } else if (nextFields.length > 0) {
          // More credentials needed (e.g. 2FA after password)
          setRequiredFields(nextFields);
          setAuthTypes(next_required || []);
          // Clear only the fields that were already submitted
          setCreds((prev) => ({
            ...prev,
            password: "", // clear password for security
            otp: "", pin: "", verification_code: "",
          }));
          const fieldList = nextFields.map((f) => FIELD_LABELS[f] || f).join(", ");
          addMsg("assistant",
            `🔑 **Additional authentication step required.**\n\n` +
            `${message}\n\n` +
            `**Now enter:** ${fieldList}`
          );
        } else {
          // Wrong credentials
          addMsg("assistant", `❌ **${message}**\n\nPlease check your credentials and try again.`);
        }
      }
    } catch (err) {
      const e = parseApiError(err);
      setError(e.message);
      addMsg("system", `❌ Error: ${e.message}`);
    } finally {
      setLoading(false);
    }
  };

  // ── ASK QUESTION ───────────────────────────────────────────────────────────
  const handleSend = async () => {
    const q = question.trim();
    if (!q || loading || authRequired) return;

    // If no active URL yet, try to analyze first
    if (!activeUrl && isProbablyUrl(urlInput.trim())) {
      addMsg("user", q);
      setQuestion("");
      await handleAnalyze(urlInput.trim());
      return;
    }

    if (!activeUrl) {
      setError("Please enter a URL in the sidebar and click Analyze URL first.");
      return;
    }

    addMsg("user", q);
    setQuestion("");
    setError("");
    setLoading(true);

    try {
      const resp = await axios.post(ASK_URL_EP, { question: q, url: activeUrl });
      const { answer, session_id } = resp.data;
      saveSession(session_id);
      addMsg("assistant", answer);
    } catch (err) {
      const e = parseApiError(err);
      if (e.status === 401) {
        setAuthRequired(true);
        setAuthTypes(e.authTypes);
        setRequiredFields(e.requiredFields || ["username", "password"]);
        setPhase("authing");
        addMsg("assistant", `🔐 **Session requires authentication.** Please provide your credentials.`);
      } else {
        setError(e.message);
        addMsg("system", `❌ Error: ${e.message}`);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  // ── RESET ──────────────────────────────────────────────────────────────────
  const handleNewChat = async () => {
    if (sessionId) {
      try { await axios.post(END_SESSION_URL, { session_id: sessionId }); } catch {}
    }
    setSessionId(""); setSessionStart(null); setActiveUrl("");
    setMessages([]); setQuestion(""); setUrlInput("");
    setError(""); setLoading(false); setPhase("idle");
    setAuthRequired(false); setAuthTypes([]); setRequiredFields([]);
    setCreds({ email: "", username: "", password: "", otp: "", pin: "", verification_code: "" });
    setUrlLocked(false);
  };

  // Fields to show in the auth form — exactly what the backend says is needed
  const fieldsToShow = requiredFields.length > 0
    ? requiredFields
    : ["username", "password"];

  const canSend = question.trim().length > 0 && !loading && !authRequired
    && (!!activeUrl || isProbablyUrl(urlInput.trim()));

  const phaseLabel = {
    idle: "STANDBY", analyzing: "SCANNING", authing: "AUTH REQ",
    chatting: "ACTIVE", blocked: "BLOCKED",
  }[phase] || "STANDBY";

  const phaseColor = {
    idle: "#4a5568", analyzing: "#ffb800", authing: "#ff4545",
    chatting: "#00ff9d", blocked: "#ff4545",
  }[phase] || "#4a5568";

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@300;400;500;700&family=Syne:wght@400;700;800&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        :root {
          --bg: #0a0c10; --panel: #0f1117; --panel2: #141720;
          --border: #1e2330; --border2: #252b3b;
          --text: #c8d3e8; --text-dim: #4a5568; --text-muted: #6b7a99;
          --accent: #00e5ff; --accent2: #7c3aed;
          --green: #00ff9d; --yellow: #ffb800; --red: #ff4545;
          --font-mono: 'JetBrains Mono', monospace;
          --font-display: 'Syne', sans-serif;
        }
        body { background: var(--bg); color: var(--text); font-family: var(--font-mono); min-height: 100vh; overflow-x: hidden; }
        body::before {
          content: ''; position: fixed; inset: 0; pointer-events: none; z-index: 0;
          background: radial-gradient(ellipse 80% 40% at 20% 0%, rgba(0,229,255,0.04) 0%, transparent 60%),
                      radial-gradient(ellipse 60% 30% at 80% 100%, rgba(124,58,237,0.06) 0%, transparent 60%);
        }
        .app-shell { position: relative; z-index: 1; display: grid; grid-template-columns: 260px 1fr; height: 100vh; overflow: hidden; }

        /* ── SIDEBAR ── */
        .sidebar { background: var(--panel); border-right: 1px solid var(--border); display: flex; flex-direction: column; overflow: hidden; }
        .sidebar-logo { padding: 20px 18px 16px; border-bottom: 1px solid var(--border); }
        .logo-mark { display: flex; align-items: center; gap: 10px; margin-bottom: 4px; }
        .logo-icon { width: 30px; height: 30px; background: linear-gradient(135deg, var(--accent), var(--accent2)); border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 15px; flex-shrink: 0; }
        .logo-text { font-family: var(--font-display); font-weight: 800; font-size: 1rem; color: #fff; letter-spacing: -0.02em; }
        .logo-sub { font-size: 0.6rem; color: var(--text-muted); letter-spacing: 0.14em; text-transform: uppercase; }

        .sidebar-section { padding: 14px 18px; border-bottom: 1px solid var(--border); }
        .section-title { font-size: 0.6rem; font-weight: 700; letter-spacing: 0.18em; text-transform: uppercase; color: var(--text-muted); margin-bottom: 10px; }

        .url-textarea { width: 100%; background: var(--panel2); border: 1px solid var(--border2); border-radius: 8px; color: var(--text); font-family: var(--font-mono); font-size: 0.71rem; padding: 8px 10px; resize: none; line-height: 1.5; transition: border-color 0.2s; }
        .url-textarea:focus { outline: none; border-color: var(--accent); box-shadow: 0 0 0 2px rgba(0,229,255,0.1); }
        .url-textarea:disabled { opacity: 0.45; cursor: not-allowed; }

        .analyze-btn { width: 100%; margin-top: 8px; padding: 9px; background: linear-gradient(135deg, rgba(0,229,255,0.12), rgba(124,58,237,0.12)); border: 1px solid var(--accent); border-radius: 8px; color: var(--accent); font-family: var(--font-mono); font-size: 0.7rem; font-weight: 700; letter-spacing: 0.1em; cursor: pointer; transition: all 0.2s; }
        .analyze-btn:hover:not(:disabled) { background: linear-gradient(135deg, rgba(0,229,255,0.22), rgba(124,58,237,0.22)); }
        .analyze-btn:disabled { opacity: 0.35; cursor: not-allowed; }

        .status-block { display: flex; flex-direction: column; gap: 7px; }
        .status-row { display: flex; align-items: center; justify-content: space-between; font-size: 0.67rem; }
        .status-key { color: var(--text-muted); }
        .status-val { font-weight: 700; font-size: 0.62rem; letter-spacing: 0.06em; padding: 2px 7px; border-radius: 4px; }

        .active-url { font-size: 0.62rem; color: var(--accent); word-break: break-all; line-height: 1.4; margin-top: 6px; padding: 6px 8px; background: rgba(0,229,255,0.05); border: 1px solid rgba(0,229,255,0.12); border-radius: 6px; }

        .sidebar-bottom { margin-top: auto; padding: 14px 18px; border-top: 1px solid var(--border); display: flex; flex-direction: column; gap: 10px; }
        .reset-btn { width: 100%; padding: 8px; background: transparent; border: 1px solid var(--border2); border-radius: 8px; color: var(--text-muted); font-family: var(--font-mono); font-size: 0.68rem; font-weight: 600; letter-spacing: 0.1em; cursor: pointer; transition: all 0.2s; }
        .reset-btn:hover:not(:disabled) { border-color: var(--red); color: var(--red); background: rgba(255,69,69,0.05); }
        .reset-btn:disabled { opacity: 0.35; cursor: not-allowed; }

        .session-timer { text-align: center; }
        .timer-label { font-size: 0.57rem; letter-spacing: 0.14em; color: var(--text-muted); margin-bottom: 4px; }
        .timer-value { font-family: var(--font-mono); font-size: 1.05rem; font-weight: 700; letter-spacing: 0.1em; margin-bottom: 5px; }
        .timer-bar-track { height: 2px; background: var(--border2); border-radius: 1px; overflow: hidden; }
        .timer-bar-fill { height: 100%; border-radius: 1px; transition: width 1s linear, background 1s ease; }

        /* ── MAIN ── */
        .main { display: flex; flex-direction: column; overflow: hidden; }

        .topbar { padding: 12px 22px; border-bottom: 1px solid var(--border); background: var(--panel); display: flex; align-items: center; justify-content: space-between; flex-shrink: 0; gap: 12px; }
        .topbar-url { font-size: 0.73rem; color: var(--text-muted); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; flex: 1; }
        .topbar-url span { color: var(--accent); }
        .session-badge { font-size: 0.6rem; letter-spacing: 0.1em; padding: 3px 9px; border-radius: 4px; font-weight: 700; flex-shrink: 0; }
        .session-badge.active { background: rgba(0,255,157,0.1); border: 1px solid rgba(0,255,157,0.3); color: var(--green); }
        .session-badge.inactive { background: rgba(74,85,104,0.15); border: 1px solid rgba(74,85,104,0.3); color: var(--text-dim); }

        /* ── AUTH PANEL ── */
        .auth-panel { padding: 16px 22px; background: rgba(255,69,69,0.04); border-bottom: 2px solid rgba(255,69,69,0.2); flex-shrink: 0; }
        .auth-header { display: flex; align-items: center; gap: 8px; margin-bottom: 12px; }
        .auth-icon-box { width: 22px; height: 22px; background: rgba(255,69,69,0.15); border: 1px solid rgba(255,69,69,0.4); border-radius: 6px; display: flex; align-items: center; justify-content: center; font-size: 11px; flex-shrink: 0; }
        .auth-title { font-family: var(--font-display); font-size: 0.78rem; font-weight: 700; color: var(--red); letter-spacing: 0.06em; }
        .auth-types-badge { font-size: 0.6rem; color: var(--text-muted); background: rgba(255,69,69,0.08); border: 1px solid rgba(255,69,69,0.15); border-radius: 4px; padding: 2px 7px; margin-left: auto; }

        .fields-needed-label { font-size: 0.65rem; color: var(--yellow); margin-bottom: 10px; letter-spacing: 0.04em; }
        .fields-needed-label strong { color: #fff; }

        .cred-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); gap: 8px; margin-bottom: 12px; }
        .cred-field { display: flex; flex-direction: column; gap: 4px; }
        .cred-label { font-size: 0.58rem; letter-spacing: 0.14em; text-transform: uppercase; color: var(--text-muted); font-weight: 700; }
        .cred-input { background: var(--panel2); border: 1px solid var(--border2); border-radius: 6px; color: var(--text); font-family: var(--font-mono); font-size: 0.75rem; padding: 8px 10px; transition: border-color 0.2s; }
        .cred-input:focus { outline: none; border-color: rgba(255,69,69,0.6); box-shadow: 0 0 0 2px rgba(255,69,69,0.1); }
        .cred-input:disabled { opacity: 0.45; }

        .submit-btn { padding: 9px 18px; background: rgba(255,69,69,0.15); border: 1px solid var(--red); border-radius: 8px; color: var(--red); font-family: var(--font-mono); font-size: 0.7rem; font-weight: 700; letter-spacing: 0.12em; cursor: pointer; transition: all 0.2s; }
        .submit-btn:hover:not(:disabled) { background: rgba(255,69,69,0.25); }
        .submit-btn:disabled { opacity: 0.35; cursor: not-allowed; }

        .captcha-note { margin-top: 10px; font-size: 0.64rem; color: var(--yellow); padding: 7px 10px; background: rgba(255,184,0,0.07); border: 1px solid rgba(255,184,0,0.2); border-radius: 6px; line-height: 1.5; }

        /* ── MESSAGES ── */
        .messages-area { flex: 1; overflow-y: auto; padding: 18px 22px; display: flex; flex-direction: column; gap: 14px; scrollbar-width: thin; scrollbar-color: var(--border2) transparent; }
        .messages-area::-webkit-scrollbar { width: 3px; }
        .messages-area::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 2px; }

        .empty-state { margin: auto; text-align: center; max-width: 360px; }
        .empty-glyph { font-size: 2.8rem; margin-bottom: 14px; display: block; }
        .empty-title { font-family: var(--font-display); font-size: 1.3rem; font-weight: 800; color: #fff; margin-bottom: 8px; letter-spacing: -0.02em; }
        .empty-desc { font-size: 0.76rem; color: var(--text-muted); line-height: 1.7; }
        .step-list { list-style: none; margin-top: 14px; display: flex; flex-direction: column; gap: 8px; text-align: left; }
        .step-item { display: flex; align-items: flex-start; gap: 10px; font-size: 0.71rem; color: var(--text-muted); }
        .step-num { width: 20px; height: 20px; background: rgba(0,229,255,0.08); border: 1px solid rgba(0,229,255,0.2); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 0.58rem; font-weight: 700; color: var(--accent); flex-shrink: 0; }

        .msg { display: flex; flex-direction: column; gap: 3px; animation: msg-in 0.22s ease; }
        @keyframes msg-in { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: translateY(0); } }
        .msg-user { align-items: flex-end; }
        .msg-assistant { align-items: flex-start; }
        .msg-system { align-items: center; }

        .msg-meta { font-size: 0.57rem; letter-spacing: 0.1em; color: var(--text-dim); text-transform: uppercase; display: flex; align-items: center; gap: 5px; }
        .msg-dot { width: 5px; height: 5px; border-radius: 50%; }
        .msg-user .msg-dot { background: var(--accent2); }
        .msg-assistant .msg-dot { background: var(--accent); }
        .msg-system .msg-dot { background: var(--text-dim); }

        .bubble { max-width: min(700px, 92%); padding: 11px 15px; border-radius: 12px; font-size: 0.81rem; line-height: 1.65; word-break: break-word; }
        .msg-user .bubble { background: #1a1040; border: 1px solid #3b1fa8; border-bottom-right-radius: 4px; color: #d4c8f8; }
        .msg-assistant .bubble { background: var(--panel2); border: 1px solid var(--border2); border-bottom-left-radius: 4px; }
        .msg-system .bubble { background: #0d1520; border: 1px solid #1e3050; border-radius: 8px; color: var(--text-muted); font-size: 0.7rem; padding: 7px 14px; max-width: 100%; text-align: center; }

        .bubble p { margin-bottom: 7px; } .bubble p:last-child { margin-bottom: 0; }
        .bubble h1,.bubble h2,.bubble h3 { margin-bottom: 7px; font-size: 0.92rem; color: #e2e8f0; }
        .bubble ul,.bubble ol { margin: 5px 0 7px 18px; } .bubble li { margin: 3px 0; }
        .bubble strong { color: var(--accent); font-weight: 700; }
        .bubble code { background: rgba(0,229,255,0.08); color: var(--accent); border-radius: 4px; padding: 1px 5px; font-size: 0.87em; }
        .bubble pre { background: #070910; border: 1px solid var(--border); border-radius: 8px; padding: 10px; overflow-x: auto; margin: 7px 0; }
        .bubble pre code { background: transparent; color: #a8d8f0; padding: 0; }
        .bubble a { color: var(--accent); }

        .thinking { display: flex; align-items: center; gap: 10px; font-size: 0.7rem; color: var(--text-muted); padding: 8px 0; }
        .thinking-dots { display: flex; gap: 4px; }
        .thinking-dot { width: 5px; height: 5px; border-radius: 50%; background: var(--accent); animation: dot-pulse 1.2s ease infinite; }
        .thinking-dot:nth-child(2) { animation-delay: 0.2s; } .thinking-dot:nth-child(3) { animation-delay: 0.4s; }
        @keyframes dot-pulse { 0%,80%,100% { opacity: 0.2; transform: scale(0.8); } 40% { opacity: 1; transform: scale(1); } }

        /* ── COMPOSER ── */
        .composer { padding: 12px 22px 16px; border-top: 1px solid var(--border); background: var(--panel); flex-shrink: 0; display: flex; flex-direction: column; gap: 8px; }
        .composer-row { display: flex; gap: 10px; align-items: flex-end; }
        .composer-textarea { flex: 1; background: var(--panel2); border: 1px solid var(--border2); border-radius: 10px; color: var(--text); font-family: var(--font-mono); font-size: 0.81rem; padding: 10px 14px; resize: none; line-height: 1.5; transition: border-color 0.2s; }
        .composer-textarea:focus { outline: none; border-color: var(--accent); box-shadow: 0 0 0 2px rgba(0,229,255,0.08); }
        .composer-textarea:disabled { opacity: 0.4; }
        .send-btn { padding: 10px 18px; background: linear-gradient(135deg, rgba(0,229,255,0.18), rgba(124,58,237,0.18)); border: 1px solid var(--accent); border-radius: 10px; color: var(--accent); font-family: var(--font-mono); font-size: 0.73rem; font-weight: 700; letter-spacing: 0.1em; cursor: pointer; transition: all 0.2s; white-space: nowrap; flex-shrink: 0; }
        .send-btn:hover:not(:disabled) { background: linear-gradient(135deg, rgba(0,229,255,0.28), rgba(124,58,237,0.28)); box-shadow: 0 0 10px rgba(0,229,255,0.18); }
        .send-btn:disabled { opacity: 0.3; cursor: not-allowed; }
        .composer-hint { font-size: 0.6rem; color: var(--text-dim); letter-spacing: 0.05em; }

        .error-bar { padding: 8px 22px; background: rgba(255,69,69,0.08); border-top: 1px solid rgba(255,69,69,0.2); font-size: 0.7rem; color: var(--red); flex-shrink: 0; }

        @media (max-width: 768px) {
          .app-shell { grid-template-columns: 1fr; grid-template-rows: auto 1fr; }
          .sidebar { flex-direction: row; flex-wrap: wrap; height: auto; border-right: none; border-bottom: 1px solid var(--border); }
        }
      `}</style>

      <div className="app-shell">
        {/* ─── SIDEBAR ─── */}
        <aside className="sidebar">
          <div className="sidebar-logo">
            <div className="logo-mark">
              <div className="logo-icon">🌐</div>
              <div className="logo-text">WebAgent AI</div>
            </div>
            <div className="logo-sub">Ollama · Playwright · FastAPI</div>
          </div>

          {/* URL Input */}
          <div className="sidebar-section">
            <div className="section-title">Target URL</div>
            <textarea
              className="url-textarea"
              rows={3}
              placeholder="https://example.com"
              value={urlInput}
              onChange={(e) => setUrlInput(e.target.value)}
              disabled={loading || urlLocked}
            />
            <button
              className="analyze-btn"
              onClick={() => handleAnalyze()}
              disabled={loading || !urlInput.trim() || urlLocked}
            >
              {loading && phase === "analyzing" ? "[ SCANNING... ]" : "[ ANALYZE URL ]"}
            </button>
          </div>

          {/* Status */}
          <div className="sidebar-section">
            <div className="section-title">Status</div>
            <div className="status-block">
              <div className="status-row">
                <span className="status-key">AGENT</span>
                <span className="status-val" style={{
                  background: `${phaseColor}18`,
                  border: `1px solid ${phaseColor}44`,
                  color: phaseColor,
                }}>{phaseLabel}</span>
              </div>
              <div className="status-row">
                <span className="status-key">SESSION</span>
                <span className="status-val" style={sessionId
                  ? { background: "rgba(0,255,157,0.1)", border: "1px solid rgba(0,255,157,0.3)", color: "var(--green)" }
                  : { background: "#1a2030", border: "1px solid #252b3b", color: "var(--text-muted)" }
                }>{sessionId ? "LIVE" : "NONE"}</span>
              </div>
              {activeUrl && <div className="active-url">{activeUrl}</div>}
            </div>
          </div>

          {/* Bottom */}
          <div className="sidebar-bottom">
            {sessionId && <SessionTimer startTime={sessionStart} />}
            <button className="reset-btn" onClick={handleNewChat} disabled={loading}>
              ↺ RESET SESSION
            </button>
          </div>
        </aside>

        {/* ─── MAIN ─── */}
        <main className="main">
          {/* Topbar */}
          <div className="topbar">
            <div className="topbar-url">
              {activeUrl
                ? <><span style={{ color: "var(--text-dim)" }}>// </span><span>{activeUrl}</span></>
                : <span style={{ color: "var(--text-dim)" }}>// No target loaded</span>
              }
            </div>
            <span className={`session-badge ${sessionId ? "active" : "inactive"}`}>
              {sessionId ? `SID: ${sessionId.slice(0, 8)}…` : "NO SESSION"}
            </span>
          </div>

          {/* Auth Panel */}
          {authRequired && (
            <div className="auth-panel">
              <div className="auth-header">
                <div className="auth-icon-box">🔐</div>
                <div className="auth-title">AUTHENTICATION REQUIRED</div>
                <div className="auth-types-badge">
                  {authTypes.length > 0 ? authTypes.join(" · ") : "username/password"}
                </div>
              </div>

              {fieldsToShow.length > 0 && (
                <div className="fields-needed-label">
                  Please provide: <strong>{fieldsToShow.map(f => FIELD_LABELS[f] || f).join(", ")}</strong>
                </div>
              )}

              <div className="cred-grid">
                {fieldsToShow.map((field) => (
                  <div key={field} className="cred-field">
                    <label className="cred-label">{FIELD_LABELS[field] || field}</label>
                    <input
                      className="cred-input"
                      type={FIELD_TYPES[field] || "text"}
                      value={creds[field] || ""}
                      onChange={(e) => setCreds((p) => ({ ...p, [field]: e.target.value }))}
                      disabled={loading}
                      placeholder={FIELD_LABELS[field] || field}
                      autoComplete={field === "password" ? "current-password" : "off"}
                      onKeyDown={(e) => { if (e.key === "Enter") handleSubmitCredentials(); }}
                    />
                  </div>
                ))}
              </div>

              <button className="submit-btn" onClick={handleSubmitCredentials} disabled={loading}>
                {loading ? "[ AUTHENTICATING... ]" : "[ SUBMIT CREDENTIALS ]"}
              </button>

              {(authTypes.includes("sso") || authTypes.includes("captcha")) && (
                <div className="captcha-note">
                  ⚠ This site uses SSO or CAPTCHA — automated login may not work.
                  Try a site with simple username/password login instead.
                </div>
              )}
            </div>
          )}

          {/* Messages */}
          <div className="messages-area">
            {messages.length === 0 ? (
              <div className="empty-state">
                <span className="empty-glyph">⬡</span>
                <div className="empty-title">AI Web Agent</div>
                <div className="empty-desc">
                  Scrape any webpage — public or login-protected — and ask questions about its content using AI.
                </div>
                <ol className="step-list">
                  {[
                    "Paste a URL in the sidebar",
                    "Click Analyze URL",
                    "Enter credentials if login is required",
                    "Ask questions about the page content",
                    "Session auto-clears after 3 hours",
                  ].map((s, i) => (
                    <li key={i} className="step-item">
                      <span className="step-num">{i + 1}</span>
                      <span>{s}</span>
                    </li>
                  ))}
                </ol>
              </div>
            ) : (
              messages.map((msg, i) => (
                <div key={i} className={`msg msg-${msg.role}`}>
                  <div className="msg-meta">
                    <span className="msg-dot" />
                    {msg.role === "user" ? "YOU" : msg.role === "system" ? "SYSTEM" : "AI"}
                    <span style={{ marginLeft: 4, opacity: 0.5 }}>
                      {new Date(msg.ts).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" })}
                    </span>
                  </div>
                  <div className="bubble">
                    {msg.role === "assistant"
                      ? <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.content}</ReactMarkdown>
                      : msg.content
                    }
                  </div>
                </div>
              ))
            )}

            {loading && (
              <div className="thinking">
                <div className="thinking-dots">
                  <div className="thinking-dot" /><div className="thinking-dot" /><div className="thinking-dot" />
                </div>
                {phase === "analyzing" ? "Scanning page…" : phase === "authing" ? "Authenticating…" : "Generating answer…"}
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Composer */}
          <div className="composer">
            <div className="composer-row">
              <textarea
                className="composer-textarea"
                placeholder={
                  authRequired ? "Complete authentication above to continue…"
                  : phase === "idle" ? "Enter a URL in the sidebar, then ask a question…"
                  : "Ask a question about the page…"
                }
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
                onKeyDown={handleKeyDown}
                rows={3}
                disabled={loading || authRequired}
              />
              <button className="send-btn" onClick={handleSend} disabled={!canSend}>
                {loading ? "…" : "SEND ↵"}
              </button>
            </div>
            <div className="composer-hint">↵ Enter to send · Shift+↵ for new line · Session auto-expires in 3h</div>
          </div>

          {error && <div className="error-bar">⚠ {error}</div>}
        </main>
      </div>
    </>
  );
}
